import{_ as e}from"./chunks/build-datahubs.B9TbUNm6.js";import{_ as a,o,c as r,ag as n}from"./chunks/framework.ePeAWSvT.js";const d="/assets/session-values-action-tree.CC0WkEtE.png",i="/assets/datahub-action-edit-save.BU_nKboG.png",s="/assets/datahub-action-edit-read.GvHFL4HZ.png",f=JSON.parse('{"title":"Endpoint Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/datahub-endpoint-config.md","filePath":"guide/datahub-endpoint-config.md"}'),l={name:"guide/datahub-endpoint-config.md"};function h(c,t,p,u,g,m){return o(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="endpoint-configuration" tabindex="-1">Endpoint Configuration <a class="header-anchor" href="#endpoint-configuration" aria-label="Permalink to &quot;Endpoint Configuration&quot;">​</a></h1><p>This section covers how to edit endpoint configurations, the inputs required for each event type, and how to parameterize URLs, bodies, and file names.</p><h2 id="edit-endpoint-configurations" tabindex="-1">Edit Endpoint Configurations <a class="header-anchor" href="#edit-endpoint-configurations" aria-label="Permalink to &quot;Edit Endpoint Configurations&quot;">​</a></h2><p><img src="'+d+'" alt="Endpoint Data Source Tab"></p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong> (A); then, select an <strong>Endpoint</strong> (B) to edit.</p><p><img src="'+e+'" alt="Data Hub endpoint selection"></p></li><li><p>Ensure the <strong>Data Source</strong> tab (C) is selected.</p></li><li><p>Select the appropriate <strong>Events</strong> tab (D) from the left column.</p></li><li><p>Select the <strong>menu</strong> icon &gt; <strong>Edit</strong> (E).</p></li><li><p>Re-configure the <strong>Endpoint Action</strong> (F) as needed.</p></li></ol><p><img src="'+i+'" alt="Edit and Save Endpoint Action"></p><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>The data required to configure an Endpoint Action is dependent on the action assigned (i.e. API Read, SQL Save, File Read, etc.). See the <a href="#endpoint-event-inputs">Endpoint Event Inputs</a> section below for detailed descriptions on each protocol.</p></div><ol start="7"><li>For Read Actions, you can use the <strong>Test Request</strong> button in the modal footer to test the action directly without saving. This opens the Test Connector modal with the request pre-populated from your current configuration.</li></ol><p><img src="'+s+'" alt="Edit Read Action Modal"></p><ol start="8"><li>When finished, select <strong>Save</strong> (G).</li></ol><div class="info custom-block"><p class="custom-block-title">NOTES</p><ul><li>You will need to configure each Endpoint Action created (e.g. if Both was selected as the Endpoint Type, then you&#39;ll need to configure the Endpoint Action for both the On Save and Get Changes events).</li><li>When a save action is created, the Common Model will automatically create an interaction to the Key. Users can create as many interactions as needed associated with the save action.</li><li>The <strong>Read URL</strong> field is critical for successful Endpoint Mapping, which you will construct next. When Mapping Endpoints, it is critical to ensure the data from a particular location within the payload gets into the Common Model. For additional information on common protocols (e.g. JSONPath, XMLPath, etc.) see the <a href="./reference-connectors.html">Connectors Catalog</a>.</li></ul></div><h2 id="endpoint-event-inputs" tabindex="-1">Endpoint Event Inputs <a class="header-anchor" href="#endpoint-event-inputs" aria-label="Permalink to &quot;Endpoint Event Inputs&quot;">​</a></h2><p>Each event type is represented by an icon in the action tree indicating the protocol and operation:</p><div class="icon-legend"><table tabindex="0"><thead><tr><th style="text-align:center;">Icon</th><th>Event Type</th></tr></thead><tbody><tr><td style="text-align:center;"><i class="fa-light fa-cloud"></i> <i class="fa-regular fa-magnifying-glass"></i></td><td>API Read (Get Changes)</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-cloud"></i> <i class="fa-regular fa-floppy-disk"></i></td><td>API Save (On Save)</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-cloud"></i> <i class="fa-regular fa-trash-can"></i></td><td>API Delete</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-database"></i> <i class="fa-regular fa-magnifying-glass"></i></td><td>SQL Read (Get Changes)</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-database"></i> <i class="fa-regular fa-floppy-disk"></i></td><td>SQL Save (On Save)</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-file"></i> <i class="fa-regular fa-magnifying-glass"></i></td><td>File Read</td></tr><tr><td style="text-align:center;"><i class="fa-light fa-file"></i> <i class="fa-regular fa-floppy-disk"></i></td><td>File Save</td></tr></tbody></table></div><p>Each event type requires different configuration inputs. The tables below describe the fields for each protocol.</p><h3 id="api-get-changes" tabindex="-1">API Get Changes <a class="header-anchor" href="#api-get-changes" aria-label="Permalink to &quot;API Get Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>A freeform label you give to the Action.</td></tr><tr><td><strong>Response Selector</strong></td><td>JSON Path or XPath query that points to where the data is on the response.</td></tr><tr><td><strong>Paging Selector</strong></td><td>JSON Path or XPath query indicating where in the response to pull the URL of the next page.</td></tr><tr><td><strong>Max Pages</strong></td><td>Limits the total number of pages that the action can return.</td></tr><tr><td><strong>Read Method</strong></td><td>The HTTP verb required by the API.</td></tr><tr><td><strong>Read URL</strong></td><td>The HTTP address required by the API. This value is concatenated to the Base URL on the Connector. See <a href="#parameterizing">Parameterizing</a> below for additional information.</td></tr><tr><td><strong>Read Body</strong></td><td>Not required, but useful for advanced searching APIs. A POST is used in order to query, and in those cases an HTTP body is used in the request. See <a href="#parameterizing">Parameterizing</a> below. Examples include SuiteQL, SOQL, OData, and calling Select Stored Procedures (Date Last Polled and Parent-Child).</td></tr></tbody></table><h3 id="api-on-save" tabindex="-1">API On Save <a class="header-anchor" href="#api-on-save" aria-label="Permalink to &quot;API On Save&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>A freeform label you give to the Action.</td></tr><tr><td><strong>Is Batch</strong></td><td>Can be toggled ON to save entities as a group (batch) instead of individually.</td></tr><tr><td><strong>Create Method</strong></td><td>The HTTP verb required by the API to insert a new record. The default verb for a Create is a POST.</td></tr><tr><td><strong>Create URL</strong></td><td>The HTTP address required by the API to insert a new record.</td></tr><tr><td><strong>Update Method</strong></td><td>The HTTP verb required by the API to update an existing record. The default method for an Update is a PATCH, but in some cases a PUT or POST can be used as well.</td></tr><tr><td><strong>Update URL</strong></td><td>The HTTP address required by the API to update existing data. The URL for an Update is usually parameterized with the ID of the record being updated.</td></tr><tr><td><strong>Update Requires Full Copy</strong></td><td>On update, this will pull a copy of the data from the API as a starting point, which the mapping then uses as the starting document (instead of a blank JSON document). This should be used when a Subscriber needs the full payload to update instead of just the changes.</td></tr></tbody></table><h3 id="api-delete" tabindex="-1">API Delete <a class="header-anchor" href="#api-delete" aria-label="Permalink to &quot;API Delete&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>A freeform label you give to the Action.</td></tr><tr><td><strong>Delete Method</strong></td><td>The HTTP verb required by the API to delete a record. The default method for a Delete is DELETE.</td></tr><tr><td><strong>Delete URL</strong></td><td>The HTTP address required by the API to delete a record. The URL for a Delete is usually parameterized with the ID of the record being deleted.</td></tr><tr><td><strong>Delete Body</strong></td><td>Optional. A collapsible Body editor allows you to specify a request body for the DELETE operation. Uses the code editor with syntax highlighting for the connector&#39;s protocol (JSON/XML).</td></tr></tbody></table><h3 id="sql-get-changes" tabindex="-1">SQL Get Changes <a class="header-anchor" href="#sql-get-changes" aria-label="Permalink to &quot;SQL Get Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>A freeform label you give to the Action.</td></tr><tr><td><strong>Read Command Type</strong></td><td>The SQL Command can be a Stored Procedure or Text (Dynamic SQL).</td></tr><tr><td><strong>Read Command</strong></td><td>For Stored Procedure, set this to the procedure name. On a Stored Procedure that can pull child items (e.g. Lines on an Order), it MUST have an input parameter called <code>@ParentId</code>. If it needs a date filter, the parameter should be called <code>@DateLastPolled</code>. For Text, an inline SQL code editor appears where you can write dynamic SQL queries with syntax highlighting.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>When using <strong>Text</strong> command type, a <strong>Copy Params to Maps</strong> button is available that automatically detects <code>@parameter</code> names in your SQL and creates corresponding property maps.</p></div><h3 id="sql-on-save" tabindex="-1">SQL On Save <a class="header-anchor" href="#sql-on-save" aria-label="Permalink to &quot;SQL On Save&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>A freeform label you give to the Action.</td></tr><tr><td><strong>Create Command Type</strong></td><td>The SQL Command can be a Stored Procedure or Text (Dynamic SQL).</td></tr><tr><td><strong>Create Command</strong></td><td>For Stored Procedure, the command is the procedure name. For Text, an inline SQL code editor appears for writing dynamic SQL with syntax highlighting.</td></tr><tr><td><strong>Update Command Type</strong></td><td>The SQL Command can be a Stored Procedure or Text (Dynamic SQL).</td></tr><tr><td><strong>Update Command</strong></td><td>For Stored Procedure, the command is the procedure name. For Text, the command is the parameterized query — use the inline SQL code editor with the <strong>Copy Params to Maps</strong> button to auto-generate property maps from <code>@parameter</code> names.</td></tr></tbody></table><h3 id="sql-delete" tabindex="-1">SQL Delete <a class="header-anchor" href="#sql-delete" aria-label="Permalink to &quot;SQL Delete&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>A freeform label you give to the Action.</td></tr><tr><td><strong>Delete Command Type</strong></td><td>The SQL Command can be a Stored Procedure or Text (Dynamic SQL).</td></tr><tr><td><strong>Delete Command</strong></td><td>If the SQL Command is Stored Procedure, then the command is the name of the Stored Procedure.</td></tr></tbody></table><h3 id="file-read-save" tabindex="-1">File Read / Save <a class="header-anchor" href="#file-read-save" aria-label="Permalink to &quot;File Read / Save&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>A freeform label you give to the Action.</td></tr><tr><td><strong>Location</strong></td><td>The folder or container name.</td></tr><tr><td><strong>File Name</strong></td><td>The name of the file.</td></tr><tr><td><strong>Delimiter</strong></td><td>The character that is used to parse the file; the default value is a comma.</td></tr></tbody></table><h2 id="additional-events-inputs" tabindex="-1">Additional Events Inputs <a class="header-anchor" href="#additional-events-inputs" aria-label="Permalink to &quot;Additional Events Inputs&quot;">​</a></h2><h3 id="receipt-replication-save" tabindex="-1">Receipt Replication Save <a class="header-anchor" href="#receipt-replication-save" aria-label="Permalink to &quot;Receipt Replication Save&quot;">​</a></h3><p>Receipt Replication allows the save status (success, failure, or both) to be written back to the publishing system, e.g. writing errors back to the source system instead of relying on the Error Logs.</p><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>A freeform label you give to the Action.</td></tr><tr><td><strong>Create Method</strong></td><td>The HTTP verb required by the API to insert a new record. The default verb for a Create is a POST.</td></tr><tr><td><strong>Create URL</strong></td><td>The HTTP address required by the API to insert a new record.</td></tr><tr><td><strong>Receipt Level</strong></td><td>Dictates which receipts get processed and written back to the publishing system (error, success, or both).</td></tr><tr><td><strong>Update Requires Full Copy</strong></td><td>On update, this will pull a copy of the data from the API as a starting point, which the mapping then uses as the starting document (instead of a blank JSON document). This should be used when a Subscriber needs the full payload to update instead of just the changes.</td></tr></tbody></table><h3 id="key-replication" tabindex="-1">Key Replication <a class="header-anchor" href="#key-replication" aria-label="Permalink to &quot;Key Replication&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>A freeform label you give to the Action.</td></tr><tr><td><strong>Update Method</strong></td><td>The HTTP verb required by the API to update an existing record. The default method for an Update is a PATCH, but in some cases a PUT or POST can be used as well.</td></tr><tr><td><strong>Update URL</strong></td><td>The HTTP address required by the API to update existing data. The URL for an Update is usually parameterized with the ID of the record being updated.</td></tr><tr><td><strong>Update Requires Full Copy</strong></td><td>On update, this will pull a copy of the data from the API as a starting point, which the mapping then uses as the starting document (instead of a blank JSON document). This should be used when a Subscriber needs the full payload to update instead of just the changes.</td></tr></tbody></table><h2 id="additional-instructions" tabindex="-1">Additional Instructions <a class="header-anchor" href="#additional-instructions" aria-label="Permalink to &quot;Additional Instructions&quot;">​</a></h2><p>Each endpoint action (Read, Save, Delete) has an <strong>Instructions</strong> tab where you can add request-shaping instructions that apply only to that specific action — most commonly custom HTTP headers, query parameters, body values, or time-zone conversion of the LastRun timestamp.</p><ol><li><p>Open the endpoint action for editing (see <a href="#edit-endpoint-configurations">Edit Endpoint Configurations</a> above).</p></li><li><p>Switch to the <strong>Instructions</strong> tab.</p></li><li><p>Select <strong>+ Add Instruction</strong> and choose an instruction type from the menu.</p></li><li><p>Fill in the type-specific fields (see <a href="#instruction-types">Instruction types</a> below).</p></li><li><p>(Save actions only) Optionally check <strong>Create</strong>, <strong>Update</strong>, or both under <strong>Runs On</strong> to scope the instruction to specific operations. Leave both unchecked to apply on every save.</p></li><li><p>Select <strong>Save</strong> in the dialog, then <strong>Save</strong> on the action.</p></li></ol><h3 id="instruction-types" tabindex="-1">Instruction types <a class="header-anchor" href="#instruction-types" aria-label="Permalink to &quot;Instruction types&quot;">​</a></h3><h4 id="header-string-value" tabindex="-1">Header / String Value <a class="header-anchor" href="#header-string-value" aria-label="Permalink to &quot;Header / String Value&quot;">​</a></h4><p>Sets a string on a request target — most commonly an HTTP header, but the <strong>Target</strong> dropdown also supports <code>QueryParameter</code>, <code>FormBody</code>, <code>PostBody</code>, <code>JwtClaim</code>, and other transport-level slots.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Target</strong></td><td>Where the value is applied (Header, QueryParameter, etc.).</td></tr><tr><td><strong>Key</strong></td><td>The header name, query-parameter name, or body-field key.</td></tr><tr><td><strong>Value</strong></td><td>The value to set. Supports <a href="#parameterizing">parameterizing</a> (e.g. <code>{PROP:Id}</code>, <code>{SYS:CurrentDateTime}</code>).</td></tr></tbody></table><p>Common use cases:</p><table tabindex="0"><thead><tr><th>Target</th><th>Key</th><th>Example Value</th><th>When to use</th></tr></thead><tbody><tr><td><code>Header</code></td><td><code>Prefer</code></td><td><code>odata.include-annotations=&quot;*&quot;</code></td><td>Override an OData annotation preference for a specific Dynamics endpoint.</td></tr><tr><td><code>Header</code></td><td><code>If-None-Match</code></td><td><code>{PROP:ETag}</code></td><td>Conditional GET using the previously stored ETag.</td></tr><tr><td><code>QueryParameter</code></td><td><code>version</code></td><td><code>2024-08</code></td><td>Pin an API version for a single endpoint.</td></tr></tbody></table><h4 id="time-zone-conversion" tabindex="-1">Time Zone Conversion <a class="header-anchor" href="#time-zone-conversion" aria-label="Permalink to &quot;Time Zone Conversion&quot;">​</a></h4><p>Shifts the LastRun timestamp into the chosen time zone before it is injected into request parameters such as <code>{SYS:DateLastPolled}</code>. Use this when the upstream API expects date/time filters in a non-UTC zone (e.g. a Dynamics tenant configured for <code>America/New_York</code>).</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Time Zone</strong></td><td>IANA-style identifier (preferred) selected from the timezone typeahead.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>This instruction does not change request headers or body content directly — it only adjusts the timestamp value used by the parameterizing engine. Combine with a <code>{SYS:DateLastPolled}</code> placeholder in your <strong>Read URL</strong> or <strong>Read Body</strong> to see the converted value reach the API.</p></div><h3 id="override-semantics" tabindex="-1">Override semantics <a class="header-anchor" href="#override-semantics" aria-label="Permalink to &quot;Override semantics&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Endpoint-level instructions <strong>replace</strong> any same-name connector-level instruction on the wire — including all values of that header. If your connector has a <code>Prefer: return=representation</code> default and your endpoint adds <code>Prefer: odata.include-annotations=&quot;*&quot;</code>, the connector default is dropped from this endpoint&#39;s request. To keep both, restate them as separate instructions on the endpoint.</p></div><p>This is intentional: it gives you a clean way to opt out of a connector-wide default for a single endpoint. See <a href="./build-connectors.html#additional-instructions">Connector-wide Instructions</a> for the broader-scope alternative.</p><h3 id="runs-on-save-actions-only" tabindex="-1">Runs On (Save actions only) <a class="header-anchor" href="#runs-on-save-actions-only" aria-label="Permalink to &quot;Runs On (Save actions only)&quot;">​</a></h3><p>A Save action can fire on <strong>Create</strong> or <strong>Update</strong>. The <strong>Runs On</strong> column lets you target an instruction to only one of those operations — e.g. set a <code>Prefer: return=representation</code> header only on Update so that POST responses stay minimal. Read and Delete actions don&#39;t expose this control because they only fire in a single operation context.</p><h2 id="parameterizing" tabindex="-1">Parameterizing <a class="header-anchor" href="#parameterizing" aria-label="Permalink to &quot;Parameterizing&quot;">​</a></h2><p>Parameterizing enables data to be dynamically passed into an action as a way of telling the mapping engine that some data needs to be injected, and potentially formatted, into the URL or Body of the API Request or a File Name. Parameterizing enables users to take the ID off the inbound message and append it to the Update message.</p><p>Instances where parameterizing can be used include:</p><ul><li>Update and Delete a record</li><li>Query date last polled from URL</li><li>Query date last polled from Body</li><li>Add Variables to a Body</li></ul><h3 id="system-parameters" tabindex="-1">System Parameters <a class="header-anchor" href="#system-parameters" aria-label="Permalink to &quot;System Parameters&quot;">​</a></h3><p>Data that comes internally to the system.</p><table tabindex="0"><thead><tr><th>Syntax</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>SYS:CurrentDateTime</code></td><td>Injects the current date/time</td><td><code>{SYS:CurrentDateTime}</code></td></tr><tr><td><code>SYS:DateLastPolled</code></td><td>Injects the LastRun timestamp from the Publisher (subject to <a href="#time-zone-conversion">Time Zone Conversion</a> when configured)</td><td><code>{SYS:DateLastPolled}</code></td></tr><tr><td><code>SYS:StartDateTime</code></td><td>Injects the time the triggering event fired</td><td><code>{SYS:StartDateTime}</code></td></tr><tr><td><code>SYS:PrimaryId</code></td><td>Injects the primary key of the record currently being processed in the target system</td><td><code>{SYS:PrimaryId}</code></td></tr><tr><td><code>SYS:ParentId</code></td><td>Injects the primary key of the parent record in the target system. Only available inside <a href="./datahub-relationships.html#child-endpoints">Child Endpoints</a> — see below</td><td><code>{SYS:ParentId}</code></td></tr></tbody></table><h4 id="when-sys-parentid-is-available" tabindex="-1">When <code>SYS:ParentId</code> is available <a class="header-anchor" href="#when-sys-parentid-is-available" aria-label="Permalink to &quot;When `SYS:ParentId` is available&quot;">​</a></h4><p><code>SYS:ParentId</code> is only populated when the action is running inside a <strong>Child Endpoint</strong> (an endpoint nested under a parent in <a href="./datahub-relationships.html#child-endpoints">Endpoint Relationships</a>). It resolves to the parent record&#39;s primary key <strong>in the system the child action is talking to</strong> (the subscribing system on saves, the publishing system on reads).</p><p>Use this table to know whether the value will resolve at runtime:</p><table tabindex="0"><thead><tr><th>Scenario</th><th><code>{SYS:ParentId}</code> resolves?</th><th>Resolves to</th></tr></thead><tbody><tr><td>Read / Save / Update / Delete on a Child Endpoint</td><td>Yes</td><td>Parent record&#39;s primary key in the connector system being called</td></tr><tr><td>Inner Read inside a Child Endpoint (loading further nested children)</td><td>Yes</td><td>The current child&#39;s primary key (becomes the parent of the inner read)</td></tr><tr><td>Key Replication update on a Child Endpoint</td><td>Yes</td><td>Parent entity&#39;s primary key in the connector system</td></tr><tr><td>Any action on the <strong>root / top-level</strong> Endpoint</td><td>No — empty</td><td>—</td></tr><tr><td>Child Endpoint action where the parent has not yet been keyed in the target system (e.g. parent save failed or was skipped)</td><td>No — empty</td><td>—</td></tr><tr><td>Child Endpoint action where there is no <code>ParentEntity</code> on the message (orphan child)</td><td>No — empty</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>On root endpoints use <code>{PK:Name}</code> or <code>{PROP:Name}</code> to get the current record&#39;s identity — <code>{SYS:ParentId}</code> is intentionally blank there because there is no parent in scope.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For <strong>child saves</strong>, <code>{SYS:ParentId}</code> resolves against the <strong>subscribing</strong> (target) system&#39;s primary key for the parent — not the publishing system&#39;s. If the parent has not been synced yet, the value will be empty; sequence the parent save first or use a pre-load action to look the parent up.</p></div><h3 id="schema-parameters" tabindex="-1">Schema Parameters <a class="header-anchor" href="#schema-parameters" aria-label="Permalink to &quot;Schema Parameters&quot;">​</a></h3><p>Data that comes off another piece of data or message that is flowing through the system.</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>CD:{Name}</code></td><td>Finds custom data with matching name and injects that value</td><td><code>{CD:CustomFieldA}</code></td></tr><tr><td><code>PROP:{Name}</code></td><td>Finds a property on the model with a matching name and injects that value</td><td><code>{PROP:FirstName}</code></td></tr><tr><td><code>PK:{Name}</code></td><td>Finds a Primary Key with the given Name for the processing system and injects that value</td><td><code>{PK:Id}</code></td></tr><tr><td><code>FK:{Name}</code></td><td>Finds a Foreign Key with the given Name for the processing System and injects that value</td><td><code>{FK:CustomerId}</code></td></tr><tr><td><code>RD:{Name}</code></td><td>Finds a Related Data item with the given Name for the processing system and injects that value</td><td><code>{RD:OpportunityId}</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>RD:</code> matches only Related Data items that belong to the record itself (without a <code>RelatedKeyName</code>) and always resolves against the subscribing system.</p></div><h3 id="variable-parameters" tabindex="-1">Variable Parameters <a class="header-anchor" href="#variable-parameters" aria-label="Permalink to &quot;Variable Parameters&quot;">​</a></h3><p>Enables users to set any static value and inject it into an action, such as a specific value within a file name or parameter within a URL.</p><table tabindex="0"><thead><tr><th>Syntax</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>VAR:{Name}</code></td><td>Finds a Variable with the given Name and injects that value</td><td><code>{VAR:SomeVariable}</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Optionally, formatting can be applied to the injected value by adding an additional <code>:{format}</code> to the placeholder, e.g. <code>{VAR:CurrentDate:yyyy-MM-dd}</code>.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./datahub-action-mapping.html">Action Mapping</a> — Map endpoint actions to Common Model properties</li><li><a href="./datahub-data-adaptation.html">Data Adaptation</a> — Transform data during reads and writes</li><li><a href="./session-values.html">Session Values</a> — Extract and reuse values across multi-step API workflows</li><li><a href="./datahub-key-scraping.html">Key Scraping</a> — Configure primary key indexing after saves</li></ul>',77)])])}const v=a(l,[["render",h]]);export{f as __pageData,v as default};
